93	const httpLoggerPlugin: FastifyPluginCallback = (fastify, _options, done) => {
94		fastify.addHook('onResponse', (request, reply, done) => {
95			if (reply.statusCode === 404) {
96				const notFoundError = new Error(
97					`Route not found: ${request.method} ${request.url}`,
98				);
99				notFoundError.name = 'NotFoundError';
100				logHttpRequest(request, reply, notFoundError);
101			} else {
102				logHttpRequest(request, reply);
103			}
104			done();
105		});
106	
107		fastify.addHook('onError', (request, reply, error, done) => {
108			logHttpRequest(request, reply, error);
109			done();
110		});
111	
112		done();
113	};
114	
115	export const fastifyHttpLogger = fp(httpLoggerPlugin, {
116		name: 'fastify-http-logger',
117	});
