184	function maskSensitiveData(data: unknown, sensitiveKeys: string[] = []): unknown {
185		if (!data || typeof data !== 'object') {
186			return data;
187		}
188	
189		if (Array.isArray(data)) {
190			return data.map((item) => maskSensitiveData(item, sensitiveKeys));
191		}
192	
193		const masked = { ...data } as Record<string, unknown>;
194	
195		for (const key in masked) {
196			if (Object.prototype.hasOwnProperty.call(masked, key)) {
197				const lowerKey = key.toLowerCase();
198	
199				if (
200					sensitiveKeys.some((sensitiveKey) =>
201						lowerKey.includes(sensitiveKey.toLowerCase()),
202					)
203				) {
204					masked[key] = '***MASKED***';
205				} else if (typeof masked[key] === 'object' && masked[key] !== null) {
206					masked[key] = maskSensitiveData(masked[key], sensitiveKeys);
207				}
208			}
209		}
210	
211		return masked;
212	}
213	
214	function getRollbarInstance(): Rollbar | null {
215		return rollbar;
216	}
