23	export function isLogLevelEnabled(
24		targetLevel: LogLevel,
25		logLevels: LogLevel[] | undefined,
26	): boolean {
27		if (!logLevels || (Array.isArray(logLevels) && logLevels?.length === 0)) {
28			return false;
29		}
30		if (logLevels.includes(targetLevel)) {
31			return true;
32		}
33		const highestLogLevelValue = logLevels
34			.map((level) => LOG_LEVEL_VALUES[level])
35			.sort((a, b) => b - a)?.[0];
36	
37		const targetLevelValue = LOG_LEVEL_VALUES[targetLevel];
38		return targetLevelValue >= highestLogLevelValue!;
39	}
