2		CallHandler,
3		ExecutionContext,
4		Injectable,
5		NestInterceptor,
6		HttpException,
7	} from '@nestjs/common';
8	import { Observable, throwError } from 'rxjs';
9	import { tap, catchError } from 'rxjs/operators';
10	
11	import { NewrelicService } from '@modules/newrelic/newrelic.service';
12	
13	@Injectable()
14	export class NewrelicInterceptor implements NestInterceptor {
15		constructor(private readonly newrelicService: NewrelicService) {}
16	
17		intercept(context: ExecutionContext, next: CallHandler): Observable<unknown> {
18			const httpCtx = context.switchToHttp();
19			const req = httpCtx.getRequest<Request>();
20			const { method, url, headers } = req;
21	
22			const baseUrl = `http://${(headers as unknown as Record<string, string>)['host'] ?? 'localhost'}`;
23			const parsedUrl = new URL(url, baseUrl);
24			const pathname = parsedUrl.pathname;
25	
26			const apiMatch = /^\/api\/v1\/([^/]+)/.exec(pathname);
27			const nonApiMatch = /^\/([^/]+)/.exec(pathname);
28			const group = apiMatch?.[1] ?? nonApiMatch?.[1] ?? 'unknown';
29	
30			const transactionName = apiMatch
31				? `${method} /api/v1/${group}`
32				: `${method} /${group}`;
33	
34			const nr = this.newrelicService.instance;
35			nr.setTransactionName(transactionName);
36			nr.addCustomAttribute('apiGroup', group);
37			nr.addCustomAttribute('path', pathname);
38			this.newrelicService.setGroup(group);
39			this.newrelicService.attachMetadata();
40	
41			const start = Date.now();
42	
43			return next.handle().pipe(
44				tap(() => {
45					const duration = Date.now() - start;
46					this.newrelicService.recordMetric('Interceptor', 'ResponseTime', duration);
47				}),
48				catchError((err: unknown) => {
49					const status = err instanceof HttpException ? err.getStatus() : 500;
50					if (status >= 500) {
51						const errorToReport =
52							err instanceof Error ? err : new Error(JSON.stringify(err));
53						nr.noticeError(errorToReport);
54					}
55					return throwError(() => err as Error);
56				}),
57			);
58		}
59	}
